SELECT
a.id id,
a.application_time applicationTime,
a.first_review_time firstReviewTime,
a.review_order_number reviewOrderNumber,
a.review_operation reviewOperation,
a.review_status reviewStatus,
a.applicant applicant,
a.first_instance firstInstance,
a.lock_status lockStatus,
a.review_application_type reviewApplicationType,
a.member_account memberAccount,
a.account_type accountType,
IF(a.locker = #{adminName}, -1, 5) reviewOperation1,
a.application_information applicationInfo,
a.before_fixing beforeFixing,
a.after_modification afterModification,
a.locker locker,
a.review_remark reviewRemark
FROM user_account_update_review a


        AND a.site_code = #{vo.siteCode}


        AND a.application_time  >=  #{vo.startApplicationTime}


        AND a.application_time  <=  #{vo.endApplicationTime}


        AND a.first_review_time  >=  #{vo.startFirstReviewTime}


        AND a.first_review_time  <=  #{vo.endFirstReviewTime}


        AND a.member_account = #{vo.memberAccount}


        AND a.account_type IN

            #{value}




        AND a.review_application_type IN

            #{value}




        AND a.review_operation = #{vo.reviewOperation}


        AND a.review_status IN

            #{value}



        AND a.applicant = #{vo.applicant}


        AND a.first_instance = #{vo.firstInstance}


        AND a.lock_status = #{vo.lockStatus}


        AND a.review_order_number = #{vo.reviewOrderNumber}




        ORDER BY applicationTime asc


        ORDER BY applicationTime desc



        ORDER BY firstReviewTime asc


        ORDER BY firstReviewTime desc


        ORDER BY reviewOperation1 asc,a.review_status ASC,a.review_operation ASC,a.review_application_type ASC, a.application_time ASC
